mapper.select:
SELECT ts.id, ts.sid, ts.school_id, ts.class_id, ts.subject_id, ts.teacher_id, ts.create_time, ts.update_time,
       s.subject_name, u.username as teacherName
FROM teaching_setting ts
LEFT JOIN subject_rel sr ON ts.subject_id = sr.id
LEFT JOIN subject s ON sr.subject_id = s.id
LEFT JOIN sys_user_school_rel u ON ts.teacher_id = u.id
WHERE ts.deleted = 0

    AND ts.school_id = #{schoolId}


    AND ts.sid = #{sid}


    AND ts.class_id = #{classId}


    AND ts.subject_id = #{subjectId}


    AND ts.teacher_id = #{teacherId}


    AND s.subject_name = #{subjectName}


    AND u.username = #{teacherName}

order by ts.create_time desc

SELECT su.id, susr.id as teacherId, susr.username as teacherName, su.mobile as teacherPhoneNumber FROM sys_user_school_rel susr LEFT JOIN sys_user su ON susr.user_id = su.id LEFT JOIN (SELECT teacher_id,'0' as deleted FROM teaching_setting WHERE deleted =0 GROUP BY teacher_id) ts ON susr.id = ts.teacher_id WHERE susr.deleted = 0 and ts.deleted = 0
AND susr.school_id = #{schoolId}
AND susr.id = #{teacherId}
AND susr.username LIKE CONCAT('%', #{teacherName}, '%')
order by susr.create_time desc
